export const NotificationCard = ({
  title,
  message,
  time,
  read,
  type,
  onPress,
}: NotificationCardProps) => {
  const { colors } = useTheme();

  const getIcon = () => {
    switch (type) {
      case 'booking':
        return {
          icon: <Calendar size={20} color={colors.infoText} />,
          bg: colors.infoBg,
        };
      case 'offer':
        return {
          icon: <Tag size={20} color={colors.maintenanceText} />,
          bg: colors.maintenanceBg,
        };
      default:
        return {
          icon: <CheckCircle size={20} color={colors.successText} />,
          bg: colors.successBg,
        };
    }
  };

  const { icon, bg } = getIcon();

  return (
    <TouchableOpacity
      onPress={onPress}
      style={[
        styles.container,
        {
          backgroundColor: colors.background,
          borderColor: colors.border,
          shadowColor: colors.shadow,
          shadowOpacity: read ? 0 : 0.05,
          shadowOffset: { width: 0, height: 2 },
          shadowRadius: 4,
          elevation: read ? 0 : 2,
        },
      ]}
