      <View style={styles.content}>
        <View style={[styles.iconContainer, { backgroundColor: bg }]}>
          {icon}
        </View>

        <View style={styles.textContainer}>
          <View style={styles.header}>
            <Text
              style={[
                styles.title,
                { color: colors.text, fontWeight: read ? '500' : 'bold' },
