      </ScrollView>

      {/* Bottom Booking Bar */}
      {selectedSlot && (
        <View style={styles.footer}>
          <View style={styles.footerInfo}>
            <Text style={styles.footerLabel}>
              {t('courtDetail.selectedSlot')}
