              mode="dropdown"
            >
              <Picker.Item label={t('roles.player')} value="player" />
              <Picker.Item label={t('roles.owner')} value="owner" />
              <Picker.Item label={t('roles.assistant')} value="assistant" />
              <Picker.Item label={t('roles.admin')} value="admin" />
            </Picker>
          </View>

          <View style={styles.methodToggle}>
            <TouchableOpacity
              style={[
                styles.methodButton,
                loginMethod === 'email' && styles.methodButtonActive,
              ]}
              onPress={() => setLoginMethod('email')}
            >
              <Mail
                size={18}
                color={
                  loginMethod === 'email'
                    ? colors.primary
                    : colors.textSecondary
                }
              />
              <Text
                style={[
                  styles.methodText,
                  loginMethod === 'email' && styles.methodTextActive,
                ]}
              >
                {t('common.email')}
              </Text>
            </TouchableOpacity>
            <TouchableOpacity
              style={[
                styles.methodButton,
                loginMethod === 'phone' && styles.methodButtonActive,
              ]}
              onPress={() => setLoginMethod('phone')}
            >
              <Phone
                size={18}
                color={
                  loginMethod === 'phone'
                    ? colors.primary
                    : colors.textSecondary
                }
              />
              <Text
                style={[
                  styles.methodText,
                  loginMethod === 'phone' && styles.methodTextActive,
                ]}
              >
                {t('common.phone')}
              </Text>
            </TouchableOpacity>
          </View>

          <TextInput
            style={styles.input}
            placeholder={
              loginMethod === 'email'
                ? t('common.enterEmail')
                : t('common.enterPhone')
            }
            placeholderTextColor={colors.textSecondary}
            value={identifier}
            onChangeText={setIdentifier}
            keyboardType={
              loginMethod === 'email' ? 'email-address' : 'phone-pad'
            }
            autoCapitalize="none"
          />

          <TouchableOpacity style={styles.submitButton} onPress={handleLogin}>
            <Text style={styles.submitButtonText}>{t('common.sendOtp')}</Text>
          </TouchableOpacity>

          <View style={styles.footer}>
            <Text style={styles.footerText}>{t('common.newUser')} </Text>
            <TouchableOpacity onPress={navigateToSignup}>
              <Text style={styles.footerLink}>{t('common.signup')}</Text>
            </TouchableOpacity>
          </View>
        </View>
      </ScrollView>
    </KeyboardAvoidingView>
  );
};

import { BellOff } from 'lucide-react-native';
import React from 'react';
import {
  FlatList,
  RefreshControl,
  SafeAreaView,
  Text,
  View,
} from 'react-native';

import { AppHeader } from '../../components/AppHeader';
import { NotificationCard } from '../../components/NotificationCard';
import { useNotificationsHook } from './notifications.hooks';
import { createStyles } from './notifications.style';

export const NotificationsScreen = () => {
  const {
    colors,
    t,
    notifications,
    isLoading,
    handleBack,
    handleNotificationPress,
    refetch,
  } = useNotificationsHook();

  const styles = createStyles(colors);

  return (
    <SafeAreaView style={styles.container}>
      <AppHeader
        title={t('notifications.title')}
        showBack={true}
        onBackPress={handleBack}
        showNotifications={false}
      />

      <View style={[styles.content, { flex: 1 }]}>
        <FlatList
          data={notifications}
          keyExtractor={item => item.id.toString()}
          contentContainerStyle={styles.listContent}
          showsVerticalScrollIndicator={false}
          refreshControl={
            <RefreshControl
              refreshing={isLoading}
              onRefresh={refetch}
              tintColor={colors.primary}
            />
          }
          ListEmptyComponent={
            !isLoading ? (
              <View style={styles.emptyContainer}>
                <BellOff size={48} color={colors.textSecondary} />
                <Text
                  style={[styles.emptyText, { color: colors.textSecondary }]}
                >
                  {t('notifications.noNotifications')}
                </Text>
              </View>
            ) : null
          }
          renderItem={({ item }) => (
            <NotificationCard
              title={item.title}
              message={item.message}
              time={item.time}
              read={item.read}
              type={item.type as any}
              onPress={() => handleNotificationPress(item.id)}
            />
          )}
        />
      </View>
    </SafeAreaView>
  );
};

import React from 'react';
import {
  SafeAreaView,
  ScrollView,
  Text,
  TextInput,
  TouchableOpacity,
  View,
} from 'react-native';

import { AppHeader } from '../../components/AppHeader';
import { useOwnerAddCourt } from './owneraddcourt.hooks';
import { createStyles } from './owneraddcourt.style';

export const OwnerAddCourtScreen = () => {
  const {
    t,
    colors,
    form,
    handleBack,
    handleChange,
    toggleDynamic,
    handleSubmit,
  } = useOwnerAddCourt();

  const styles = createStyles(colors);

  return (
    <SafeAreaView style={styles.container}>
      <AppHeader
        title={t('ownerAddCourt.title')}
        showBack
        onBackPress={handleBack}
        showLogo={false}
      />
      <ScrollView style={styles.scrollView}>
        <View style={styles.content}>
          <View style={styles.inputGroup}>
            <Text style={[styles.inputLabel, { color: colors.textSecondary }]}>
              {t('ownerAddCourt.courtName')}
            </Text>
            <TextInput
              style={[
                styles.input,
                { borderColor: colors.border, color: colors.text },
              ]}
              value={form.courtName}
              onChangeText={val => handleChange('courtName', val)}
            />
          </View>

          <View style={styles.inputGroup}>
            <Text style={[styles.inputLabel, { color: colors.textSecondary }]}>
              {t('ownerAddCourt.location')}
            </Text>
            <TextInput
              style={[
                styles.input,
                { borderColor: colors.border, color: colors.text },
              ]}
              value={form.location}
              onChangeText={val => handleChange('location', val)}
            />
          </View>

          <View style={styles.inputGroup}>
            <Text style={[styles.inputLabel, { color: colors.textSecondary }]}>
              {t('ownerAddCourt.gameType')}
            </Text>
            <TextInput
              style={[
                styles.input,
                { borderColor: colors.border, color: colors.text },
              ]}
              value={form.gameType}
              onChangeText={val => handleChange('gameType', val)}
            />
          </View>

          <View style={styles.row}>
            <View style={[styles.inputGroup, styles.halfInput]}>
              <Text
                style={[styles.inputLabel, { color: colors.textSecondary }]}
              >
                {t('ownerAddCourt.minDuration')}
              </Text>
              <TextInput
                style={[
                  styles.input,
                  { borderColor: colors.border, color: colors.text },
                ]}
                value={form.minDuration}
                onChangeText={val => handleChange('minDuration', val)}
                keyboardType="numeric"
              />
            </View>
            <View style={[styles.inputGroup, styles.halfInput]}>
              <Text
                style={[styles.inputLabel, { color: colors.textSecondary }]}
              >
                {t('ownerAddCourt.maxDuration')}
              </Text>
              <TextInput
                style={[
                  styles.input,
                  { borderColor: colors.border, color: colors.text },
                ]}
                value={form.maxDuration}
                onChangeText={val => handleChange('maxDuration', val)}
                keyboardType="numeric"
              />
            </View>
          </View>

          <TouchableOpacity
            style={styles.checkboxRow}
            onPress={toggleDynamic}
            activeOpacity={0.8}
          >
            <View
              style={{
                width: 20,
                height: 20,
                borderWidth: 2,
                borderColor: colors.primary,
                backgroundColor: form.allowDynamic
                  ? colors.primary
                  : 'transparent',
                borderRadius: 4,
              }}
            />
            <Text style={[styles.checkboxLabel, { color: colors.text }]}>
              {t('ownerAddCourt.allowDynamic')}
            </Text>
          </TouchableOpacity>

          <View style={styles.inputGroup}>
            <Text style={[styles.inputLabel, { color: colors.textSecondary }]}>
              {t('ownerAddCourt.facilities')}
            </Text>
            <TextInput
              style={[
                styles.input,
                { borderColor: colors.border, color: colors.text },
              ]}
              value={form.facilities}
              onChangeText={val => handleChange('facilities', val)}
            />
          </View>

          <View style={styles.inputGroup}>
            <Text style={[styles.inputLabel, { color: colors.textSecondary }]}>
              {t('ownerAddCourt.status')}
            </Text>
            {/* Mock simple select using text input for now */}
            <TextInput
              style={[
                styles.input,
                { borderColor: colors.border, color: colors.text },
              ]}
              value={form.status}
              onChangeText={val => handleChange('status', val)}
            />
          </View>

          <TouchableOpacity
            style={[styles.submitButton, { backgroundColor: colors.primary }]}
            onPress={handleSubmit}
          >
            <Text style={[styles.submitButtonText, { color: colors.white }]}>
              {t('ownerAddCourt.addCourt')}
            </Text>
          </TouchableOpacity>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
};

